import{_ as e,c as t,o as p,ae as r}from"./chunks/framework.BvcDoAct.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ja-jp/Management2/PART2/10.md","filePath":"ja-jp/Management2/PART2/10.md"}'),o={name:"ja-jp/Management2/PART2/10.md"};function n(S,a,i,s,G,h){return p(),t("div",null,[...a[0]||(a[0]=[r('<p>► 2023/04</p><h2 id="bmsgに共鳴する仲間-を巻き込むパーティー開催" tabindex="-1">&quot;BMSGに共鳴する仲間”を巻き込むパーティー開催 <a class="header-anchor" href="#bmsgに共鳴する仲間-を巻き込むパーティー開催" aria-label="Permalink to &quot;&quot;BMSGに共鳴する仲間”を巻き込むパーティー開催&quot;">​</a></h2><p>#G&amp;G #関係性構築 #仲間づくり</p><h3 id="「正しく夢を見て、それに向かって正しく努力して、正しく仲間を増やして、正しくそれを成していくっていうことをビジネス的にも人生的にも推奨したい」" tabindex="-1">「正しく夢を見て、それに向かって正しく努力して、正しく仲間を増やして、正しくそれを成していくっていうことをビジネス的にも人生的にも推奨したい」 <a class="header-anchor" href="#「正しく夢を見て、それに向かって正しく努力して、正しく仲間を増やして、正しくそれを成していくっていうことをビジネス的にも人生的にも推奨したい」" aria-label="Permalink to &quot;「正しく夢を見て、それに向かって正しく努力して、正しく仲間を増やして、正しくそれを成していくっていうことをビジネス的にも人生的にも推奨したい」&quot;">​</a></h3><p><strong>4月上旬、BMSGは関係者を招いたパーティー「Greeting&amp;Gathering」(以下、「G&amp;G」)を開催した。3期目半ばに差し掛かったタイミングで、関係各社に感謝とあいさつを伝えることを目的としたものだった。こうしたパーティーの開催自体は珍しいものではないが、「G&amp;G」の場合は会場の演出からBMSGのアーティストやスタッフのホスピタリティーまで、全てにおいてBMSGのカラーに彩られていた。ベースはビジネスの関係でありながら、何よりも「すごく楽しい」ムードにあふれた空間だった。SKY-HIは、なぜこのパーティーを開催したのか。そして、なぜ「すごく楽しい」空間が可能だったのか。</strong></p><p>BMSGの設立から2年半がたち、おかげさまでBE:FIRSTや自分たちソロアーティストを応援してくれる方々やBMSGに共鳴してくれる方々が、音楽やメディア関係に限らず、各所にいてくださる状況になりました。特に昨年9月の「BMSG FES」を成功させてからはその状況がより広がったと感じます。シンプルに「応援」してくださるだけでもありがたいのですが、恐らく今後はさらに皆さんを「仲間」として巻き込んで進んでいく必要があると考えています。</p><p>音楽業界や芸能界だけではないと思いますが、1990年代や2000年代にあった「わくわく」の勢いは今、どんどん減速しています。そのなかで、BE:FIRSTやMAZZEL、ソロアーティストたちを勢いに乗せていくためには、業界の方々に「今、BMSGって勢いがあるね」と感じていただく必要が絶対にあると思ったんです。</p><p>新型コロナウイルス禍が続くなか、各社がこうした外部の方を招くようなパーティーを自粛していたため、「今がチャンスだ!」と。やっぱり景気が悪いよりいいほうが皆さんもお好きでしょうし、BMSGとしてそのムードを表に出していこうという思いがありました。</p><h3 id="能動的に楽しんでくれたアーティストたち" tabindex="-1">能動的に楽しんでくれたアーティストたち <a class="header-anchor" href="#能動的に楽しんでくれたアーティストたち" aria-label="Permalink to &quot;能動的に楽しんでくれたアーティストたち&quot;">​</a></h3><p><strong>エントランスではSKY-HI自身がゲストを出迎え、会場内ではスタッフのみならずアーティストも関係者へのあいさつや歓談を行っていた。パーティー半ばのShowcaseでは、社長であるSKY-HIを筆頭に、まだトレーニーのREIKOまでがステージでのミニライブなども披露した。SKY-HI自身が社長でありアーティストでもあるゆえか、アーティストもBMSGの一員としてホスト意識があること、さらにビジネス関係者が集まるShowcaseでもものおじしないステージを見せたことも、BMSGならではの空気感をつくっていた。</strong></p><p>そのあたりは、いい意味で完全に社風ですね。社長が自分(アーティストのSKY-HI)であることのメリットとデメリットがあると思うんですが、こうした場が怖くないっていうのは大きなメリットだと思います。さらにBMSGの良さだと感じたのが、アーティストたちもすごく能動的に楽しんでくれていたことです。</p><p>アーティストとして考えると、関係者が集う場でのライブって、どうしてもお客様へのあいさつ、言ってしまえば接待的な要素が強いこともあると思うんです。自分もそうした場をたくさん見てきたし、そうしたステージに立ったことだってたくさんある。だからBMSGのアーティストたちのステージをどきどきしながら見ていたんですが、こういったパーティーで見たことないくらいみんな楽しそうで、会場もめちゃくちゃ盛り上がりました。</p><p>なんでしょう。全員が「楽しいものをつくろう」っていう空気が強いんでしょうね。「今日は大事な日だからしっかりね!」みたいなことは言いたくなかったし、言わなかったんですが、本当に全員がいいステージを見せてくれました。</p><p>最初にステージに上がったのはコア(Novel Core)だったんですが、本当に素晴らしくて。ラッパーに必要な行動として「空気を読むこと」と「あえて空気を読まないこと」があるんですが、それをあの場で見事に両立していた。コアにそのことを伝えたら「今日BMSGがこういうパーティーを開いて、(Showcaseの)1発目が俺ってことは、こういうライブを見せるのが俺だ、と思いまして、へへへ(笑)」って。本当に聡明だし、かっこいいし、感謝しかないですね。REIKOも見事にやりきってくれました。関係者向けパーティーでのライブって決してやりやすくないんです。ましてや、まだデビュー前の新人からしたら、なかなかの緊張感だったと思いますが、すごく振り切ってパフォーマンスしてくれて、めちゃくちゃかっこよかったですね。edhiii boiも気合いを入れてしっかりとやり切ってくれて、初めて見た方がひょっとしたら1番多かったアクトなんですが、たくさんのリアクションをゲストの方々からもいただきました。</p><p>逆に(Aile The)Shotaは、ああいう場であえて力を抜いてステージに現れたのが最高でしたし、「LOVE」というテーマのもと、最後に上がる自分にうまくつなげてくれるという完璧な流れでしたね。「これはやるしかねえ!」とステージに向かいました。『D.U.N.K.』をパフォーマンスし、上手から下手まで走り回ったんですが、気がついたらアーティストたちまでステージに上がって、自分の後ろで踊っていて(笑)。めっちゃうれしかったし、めっちゃありがたいし、めっちゃ楽しいし、後ろを見ながら「なんていい会社なんだ!」と思いましたし、その空気感が想像以上に来てくださった皆さんに伝わっている感じがありました。</p><p>今、アーティストに対しては、本当にいいことに「現場が楽しい」という成功体験を多くつくれている状況です。「G&amp;G」でも、会社のパーティーなんだからぴしっとしないと怒られるみたいな空気がなく、伸び伸びしていました。もちろんぱりっとしているほうが安心な側面はあるので、今後への課題感も感じているんですが、伸び伸びと育つと、ああいう現場でも伸び伸びとしてくれるから、お客様も伸び伸びと楽しむ空気がつくれるんだなと、今すごく感じていますね。来期のBMSGが掲げるビジネス上のテーマは「楽しく」にしました。</p><p>今回のパーティーを通して、自分の1番大きな仕事ってやっぱり「楽しいな」「楽しそうだな」って思ってもらうことだと改めて感じたんですよ。</p><h3 id="正しく夢見て正しく努力し···" tabindex="-1">正しく夢見て正しく努力し··· <a class="header-anchor" href="#正しく夢見て正しく努力し···" aria-label="Permalink to &quot;正しく夢見て正しく努力し···&quot;">​</a></h3><p><strong>「Greeting&amp;Gathering」とは耳慣れない言葉だが、この命名はSKY-HI自身によるものだという(BMSGの4文字のうちの「G」を使用)。文字通り、各業界各社に点在する、BMSGを応援する仲間が1カ所に集ったわけだが、最後にそうした仲間をSKY-HI自身がどう捉えているのかを聞いてみた。</strong></p><p>ありがたいことにBMSGを助けてくださる方、一緒にお仕事をし てくださる方々が、大手企業の方であっても、ドライにビジネスとしてではない感じで一緒にお仕事ができる関係性なんです。そこには仕事というよりも、「みんなで仲間を増やして頑張ろう」みたいな、ちょっと少年マンガ感も感じるんですよ。そういう感じが好きな大人の方っていうのは世の中にたくさんいて、紛れもなく僕もそうだし「『ONEPIECE』症候群」って言えばいいんでしょうかね。何バカなことを大人にもなって言ってるんだ、と言う反応のほうが正しいとは思うんですが(笑)、でも、少年マンガっぽい生き方って僕も好きだし、推奨します。</p><p>正しく夢を見て、それに向かって正しく努力して、正しく仲間を増やして、正しくそれを成していくっていうのは本当にビジネス的な意味においても、人生的な意味においても、推奨したい。それに、そうしたマインドにシンパシーを感じてくれる方だと、ただビジネスだけではなく、仲間として一緒に仕事ができる感じがあります。その輪を今後もどんどん広げていきたいですね。</p>',21)])])}const d=e(o,[["render",n]]);export{c as __pageData,d as default};
